from typing import List

def word_search(board: List[List[str]], word: str) -> bool:
    rows = len(board)
    if rows == 0:
        return False
    cols = len(board[0])
    if cols == 0:
        return False

    if not word:
        return True

    # If the word is longer than the total number of cells, it cannot be found
    if len(word) > rows * cols:
        return False

    directions = [
        (-1, 0), (1, 0), (0, -1), (0, 1),  # Up, Down, Left, Right
        (-1, -1), (-1, 1), (1, -1), (1, 1) # Top-Left, Top-Right, Bottom-Left, Bottom-Right
    ]

    for r in range(rows):
        for c in range(cols):
            # Check if the current cell matches the first letter of the word
            if board[r][c] == word[0]:
                # If it matches, try to search in all 8 directions
                for dr, dc in directions:
                    k = 0  # Index for the current character in the word
                    curr_r, curr_c = r, c

                    # Iterate through the word, checking each character
                    while k < len(word):
                        # Check if current coordinates are within board boundaries
                        if not (0 <= curr_r < rows and 0 <= curr_c < cols):
                            break  # Out of bounds, this direction fails

                        # Check if the character on the board matches the character in the word
                        if board[curr_r][curr_c] != word[k]:
                            break  # Mismatch, this direction fails

                        # Move to the next character in the word and the next cell in the current direction
                        k += 1
                        curr_r += dr
                        curr_c += dc

                    # If k reached len(word), it means the entire word was found in this direction
                    if k == len(word):
                        return True  # Word found

    # If no word was found after checking all starting points and directions
    return False
